\begin{align}
\Psi(\Theta) &= \Phi = \mathcal{O} \times \mathcal{X} \times \mathcal{I} : \text{Magic Transformation} \\
\Phi(\mathcal{E}, \mathcal{M}, \mathcal{P}) &\rightarrow \Theta(\mathcal{X}, \mathcal{O}, \mathcal{I}) : \text{Complete Phenomenon Mapping}
\end{align}
